+package io.quarkiverse.mcp.server.runtime.tracing;
+
+import java.util.Collections;
+
+import jakarta.inject.Singleton;
+
+import io.opentelemetry.api.OpenTelemetry;
+import io.opentelemetry.api.common.AttributeKey;
